// ...imports remain the same

const Feedback = () => {
  const autoplay = useRef(Autoplay({ delay: 5000 }));
  const [embla, setEmbla] = useState<EmblaCarouselType | null>(null);
  const [selectedIndex, setSelectedIndex] = useState(0);

  const feedbacks = [
    {
      id: 1,
      quote:
        "The ERP solution transformed our operations, making everything more efficient and transparent. Our team is now more productive than ever",
      author: "Michael Smith",
      image: People1,
      position: "Operations Director",
    },
    {
      id: 2,
      quote:
        "The integration process was seamless, and the support team was incredibly helpful. This software has truly streamlined our workflows.",
      author: "Sarah Brown",
      image: People2,
      position: "CFO",
    },
    {
      id: 3,
      quote:
        "We've seen significant improvements in our reporting and analytics since implementing this ERP system. Highly recommended",
      author: "Emily Johnson",
      image: People3,
      position: "IT Manager",
    },
  ];

  useEffect(() => {
    if (!embla) return;
    const onSelect = () => setSelectedIndex(embla.selectedScrollSnap());
    embla.on("select", onSelect);
    return () => embla.off("select", onSelect);
  }, [embla]);

  return (
    <div
      id="feedback"
      className="w-full max-w-[1440px] mx-auto py-10 md:py-12 lg:py-14 px-4"
    >
      <div className="w-full mx-auto">
        <h1 className="text-center text-2xl sm:text-3xl md:text-4xl font-black leading-tight mb-8 sm:mb-10 md:mb-12">
          Trusted feedback from
          <br />
          our Peoples
        </h1>

        <div className="relative">
          <Carousel
            getEmblaApi={setEmbla}
            withControls
            slideSize="100%"
            plugins={[autoplay.current]}
            onMouseEnter={autoplay.current.stop}
            onMouseLeave={autoplay.current.reset}
            classNames={{
              root: classes.carousel,
              controls: classes.controls,
              control: classes.control,
            }}
            emblaOptions={{
              loop: true,
              align: "center",
              containScroll: "trimSnaps",
            }}
            nextControlIcon={<ArrowRight className={classes.controlIcon} />}
            previousControlIcon={<ArrowLeft className={classes.controlIcon} />}
          >
            {feedbacks.map((feedback) => (
              <Carousel.Slide key={feedback.id}>
                <div className="relative mt-8 sm:mt-16 flex flex-col md:flex-row items-center md:items-start justify-center gap-6 md:gap-10 px-4 sm:px-8 md:px-16 lg:px-20">
                  {/* People Image */}
                  <div className="w-48 sm:w-64 md:w-80 lg:w-[400px] z-10 flex justify-center">
                    <img
                      src={feedback.image}
                      alt={feedback.author}
                      className="w-full h-auto object-cover rounded-lg"
                    />
                  </div>

                  {/* Content */}
                  <div className="relative w-full bg-black/20 rounded-lg p-6 sm:p-8 md:p-10 lg:p-12 flex flex-col justify-center items-start text-left">
                    <span className="absolute -top-20 left-0 w-48 h-48 sm:w-64 sm:h-64 rounded-full bg-gradient-to-b from-black via-black to-black/30"></span>
                    <p className="text-lg sm:text-xl md:text-2xl font-black text-white leading-relaxed z-10">
                      {feedback.quote}
                    </p>

                    {/* Name */}
                    <div className="mt-6 z-10">
                      <p className="text-base sm:text-lg md:text-xl font-bold text-white/90">
                        {feedback.author}
                      </p>
                      <p className="text-sm text-white/70">
                        {feedback.position}
                      </p>
                    </div>
                  </div>
                </div>
              </Carousel.Slide>
            ))}
          </Carousel>

          {/* Dot Indicators */}
          <div className="flex justify-center mt-6 gap-2">
            {feedbacks.map((_, index) => (
              <button
                key={index}
                onClick={() => embla?.scrollTo(index)}
                className={`w-3 h-3 rounded-full transition-all duration-300 ${
                  index === selectedIndex ? "bg-white" : "bg-neutral-700"
                }`}
                aria-label={`Go to slide ${index + 1}`}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Feedback;
